#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <unistd.h>
#include <sys/time.h>

__inline__ uint64_t rdtsc() 
{
     uint32_t lo, hi;
     __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
     return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

#define M_SEED 9

#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int rows, cols;
int* data;
int** wall;
int* result;

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void init(int argc, char** argv)
{
	if(argc==3){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
	}else{
                printf("Usage: pathfiner width num_of_steps\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

__global__ void pathfinder_kernel(int* dst, int* src, int* wall, int cols, int row_offset)
{
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min_val = src[n];
    if (n > 0) {
        int left = src[n-1];
        if (left < min_val) min_val = left;
    }
    if (n < cols-1) {
        int right = src[n+1];
        if (right < min_val) min_val = right;
    }
    dst[n] = wall[row_offset + n] + min_val;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int min;

    dst = result;
    src = new int[cols];

    // CUDA setup
    int *d_data, *d_src, *d_dst;
    cudaError_t err;

    err = cudaMalloc(&d_data, rows*cols*sizeof(int));
    if (err != cudaSuccess) fatal("cudaMalloc d_data");
    err = cudaMalloc(&d_src, cols*sizeof(int));
    if (err != cudaSuccess) fatal("cudaMalloc d_src");
    err = cudaMalloc(&d_dst, cols*sizeof(int));
    if (err != cudaSuccess) fatal("cudaMalloc d_dst");

    err = cudaMemcpy(d_data, data, rows*cols*sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) fatal("cudaMemcpy d_data");

    err = cudaMemcpy(d_src, result, cols*sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) fatal("cudaMemcpy d_src");

    dim3 block(256);
    dim3 grid((cols + 255) / 256);

    pin_stats_reset();
    for (int t = 0; t < rows-1; t++) {
        temp = src;
        src = dst;
        dst = temp;

        int *d_temp = d_src;
        d_src = d_dst;
        d_dst = d_temp;

        pathfinder_kernel<<<grid, block>>>(d_dst, d_src, d_data, cols, (t+1)*cols);
    }

    cudaDeviceSynchronize();
    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    // Copy result back if computation occurred
    if (rows > 1) {
        err = cudaMemcpy(dst, d_dst, cols*sizeof(int), cudaMemcpyDeviceToHost);
        if (err != cudaSuccess) fatal("cudaMemcpy result");
    }

#ifdef BENCH_PRINT

    for (int i = 0; i < cols; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; i < cols; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    cudaFree(d_data);
    cudaFree(d_src);
    cudaFree(d_dst);

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}
